--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -995,6 +995,55 @@
-function drawOutline(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  ctx.strokeStyle = '#1a1018'; // Outline color (dark)
-  ctx.lineWidth = s * 0.15;
-  ctx.strokeRect(x, y, 16 * s, 24 * s);
-}
+function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, width: number, height: number, baseColor: string) {
+  // Parameters:
+  // ctx: canvas context
+  // x,y: top-left position
+  // s: scale (pixel size)
+  // width,height: wall size in pixels
+  // baseColor: base wall color in hex string (e.g. "#7a4f3a")
+
+  // Convert hex color to RGB
+  function hexToRgb(hex: string) {
+    const bigint = parseInt(hex.slice(1), 16);
+    const r = (bigint >> 16) & 255;
+    const g = (bigint >> 8) & 255;
+    const b = bigint & 255;
+    return { r, g, b };
+  }
+
+  // Convert RGB to hex string
+  function rgbToHex(r: number, g: number, b: number) {
+    return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
+  }
+
+  // Clamp value between 0 and 255
+  function clamp(v: number) {
+    return Math.max(0, Math.min(255, v));
+  }
+
+  const brickWidth = 16 * s;
+  const brickHeight = 8 * s;
+  const mortarThickness = 1 * s;
+
+  const rgbBase = hexToRgb(baseColor);
+
+  // Number of bricks horizontally and vertically
+  const bricksX = Math.ceil(width / brickWidth);
+  const bricksY = Math.ceil(height / brickHeight);
+
+  // Draw bricks with color variation and mortar lines
+  for (let by = 0; by < bricksY; by++) {
+    for (let bx = 0; bx < bricksX; bx++) {
+      // Brick position with offset every other row for staggered pattern
+      const offsetX = (by % 2) * (brickWidth / 2);
+      const brickX = x + bx * brickWidth - offsetX;
+      const brickY = y + by * brickHeight;
+
+      // Skip bricks fully outside the wall width
+      if (brickX + brickWidth < x || brickX > x + width) continue;
+
+      // Random color variation ±10 per channel
+      function randShade(base: number) {
+        return clamp(base + (Math.floor(Math.random() * 21) - 10));
+      }
+      const r = randShade(rgbBase.r);
+      const g = randShade(rgbBase.g);
+      const b = randShade(rgbBase.b);
+      const brickColor = rgbToHex(r, g, b);
+
+      // Draw brick rectangle
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(brickX, brickY, brickWidth, brickHeight);
+
+      // Draw mortar lines (lighter 1px lines)
+      ctx.fillStyle = "rgba(255,255,255,0.15)";
+      // Horizontal mortar line at bottom of brick
+      ctx.fillRect(brickX, brickY + brickHeight - mortarThickness, brickWidth, mortarThickness);
+      // Vertical mortar line at right edge of brick
+      ctx.fillRect(brickX + brickWidth - mortarThickness, brickY, mortarThickness, brickHeight);
+    }
+  }
+
+  // Draw shadow gradient overlay (darker bottom, lighter top)
+  const grad = ctx.createLinearGradient(x, y, x, y + height);
+  grad.addColorStop(0, "rgba(255,255,255,0.15)"); // subtle highlight top
+  grad.addColorStop(1, "rgba(0,0,0,0.3)"); // shadow bottom
+  ctx.fillStyle = grad;
+  ctx.fillRect(x, y, width, height);
+
+  // Draw subtle highlight line at top edge
+  ctx.strokeStyle = "rgba(255,255,255,0.3)";
+  ctx.lineWidth = 1 * s;
+  ctx.beginPath();
+  ctx.moveTo(x, y + 0.5 * s);
+  ctx.lineTo(x + width, y + 0.5 * s);
+  ctx.stroke();
+}
+
